import { useEffect, useState } from 'react'

/* ──────────────────────────────────────────────
 * HelpArticleTOC
 *
 * Reads the rendered article DOM (h2 / h3 with ids generated by
 * rehype-slug at build time) and builds a sticky table of contents
 * with an active-section highlight driven by IntersectionObserver.
 *
 * The DOM scan is the only useEffect here — it has to run after MDX
 * lazy-loads the article. The state it produces is then driven
 * declaratively in the render path.
 * ──────────────────────────────────────────── */

interface TocItem {
  id: string
  text: string
  level: 2 | 3
}

interface HelpArticleTOCProps {
  /** Re-scan when this changes (e.g. on slug/locale switch). */
  scanKey: string
  /** CSS selector of the article body to scan. */
  bodySelector: string
}

function collectHeadings(bodySelector: string): TocItem[] {
  const root = document.querySelector(bodySelector)
  if (!root) return []
  const nodes = root.querySelectorAll<HTMLHeadingElement>('h2[id], h3[id]')
  const items: TocItem[] = []
  for (const node of nodes) {
    const id = node.id
    const text = node.textContent?.trim() ?? ''
    if (!id || !text) continue
    items.push({ id, text, level: node.tagName === 'H2' ? 2 : 3 })
  }
  return items
}

export default function HelpArticleTOC({ scanKey, bodySelector }: HelpArticleTOCProps) {
  const [items, setItems] = useState<TocItem[]>([])
  const [activeId, setActiveId] = useState<string | null>(null)

  // Scan the DOM once the MDX article has rendered. Use a microtask
  // tick + a short retry: lazy MDX modules can resolve after the
  // first paint. The retry stops as soon as we find any headings.
  useEffect(() => {
    let cancelled = false
    let timeoutId: ReturnType<typeof setTimeout> | null = null

    function tryCollect(attempt: number): void {
      if (cancelled) return
      const collected = collectHeadings(bodySelector)
      if (collected.length > 0 || attempt >= 5) {
        setItems(collected)
        setActiveId(collected[0]?.id ?? null)
        return
      }
      timeoutId = setTimeout(() => tryCollect(attempt + 1), 80)
    }

    tryCollect(0)

    return () => {
      cancelled = true
      if (timeoutId !== null) clearTimeout(timeoutId)
    }
  }, [bodySelector, scanKey])

  // Track which heading is currently in view so the TOC can highlight it.
  useEffect(() => {
    if (items.length === 0) return
    const elements = items
      .map((i) => document.getElementById(i.id))
      .filter((el): el is HTMLElement => el !== null)
    if (elements.length === 0) return

    const observer = new IntersectionObserver(
      (entries) => {
        const visible = entries
          .filter((e) => e.isIntersecting)
          .sort((a, b) => a.boundingClientRect.top - b.boundingClientRect.top)
        if (visible[0]?.target.id) {
          setActiveId(visible[0].target.id)
        }
      },
      { rootMargin: '-20% 0px -70% 0px', threshold: 0 },
    )

    for (const el of elements) observer.observe(el)
    return () => observer.disconnect()
  }, [items])

  if (items.length === 0) {
    return null
  }

  function handleSelectChange(event: React.ChangeEvent<HTMLSelectElement>): void {
    const id = event.target.value
    if (!id) return
    setActiveId(id)
    const el = document.getElementById(id)
    if (el) {
      el.scrollIntoView({ behavior: 'smooth', block: 'start' })
      history.replaceState(null, '', `#${id}`)
    }
  }

  return (
    <>
      {/* Mobile: a "Jump to" select. */}
      <div className="lg:hidden mb-6">
        <label htmlFor="help-toc-mobile" className="block text-xs font-medium uppercase tracking-wider text-muted-foreground mb-2">
          On this page
        </label>
        <select
          id="help-toc-mobile"
          value={activeId ?? ''}
          onChange={handleSelectChange}
          className="w-full rounded-xl border border-border bg-background px-3 py-2.5 text-sm text-foreground transition-colors hover:border-input focus:border-input focus:outline-none"
        >
          {items.map((item) => (
            <option key={item.id} value={item.id}>
              {item.level === 3 ? '  · ' : ''}
              {item.text}
            </option>
          ))}
        </select>
      </div>

      {/* Desktop: sticky sidebar TOC. */}
      <nav className="max-lg:hidden sticky top-24 self-start" aria-label="Table of contents">
        <p className="text-xs font-semibold uppercase tracking-wider text-muted-foreground mb-3">
          On this page
        </p>
        <ul className="flex flex-col gap-1 text-sm border-l border-border">
          {items.map((item) => {
            const isActive = item.id === activeId
            const indent = item.level === 3 ? 'pl-7' : 'pl-4'
            return (
              <li key={item.id}>
                <a
                  href={`#${item.id}`}
                  className={`relative block py-1.5 ${indent} pr-2 transition-colors ${
                    isActive
                      ? 'text-foreground font-medium'
                      : 'text-muted-foreground hover:text-foreground'
                  }`}
                  onClick={() => setActiveId(item.id)}
                >
                  {isActive && (
                    <span
                      aria-hidden="true"
                      className="absolute -left-px top-1.5 bottom-1.5 w-0.5 rounded-full bg-primary"
                    />
                  )}
                  {item.text}
                </a>
              </li>
            )
          })}
        </ul>
      </nav>
    </>
  )
}
